  if (typeof subtitleText === "string" && subtitleText) {
    return [subtitleText];
  }

  return [];
};

const destroyInstance = (id) => {
  const instance = instances.get(id);
  if (instance && typeof instance.destroy === "function") {
    try {
      instance.destroy();
    } catch (error) {
      console.error("Failed to destroy Typed instance:", error);
    }
  }

  instances.delete(id);

  const element = document.getElementById(id);
  if (element) {
    element.innerHTML = "";
  }
};

const createTyped = (id, strings, options) => {
  if (typeof window.Typed === "undefined") {
    return;
  }

  if (!document.getElementById(id)) {
    return;
  }

  destroyInstance(id);

  const instance = new window.Typed(`#${id}`, {
    ...options,
    strings,
  });

  instances.set(id, instance);
};

const subtitleConfig = theme?.home_banner?.subtitle || {};
const hitokotoConfig = subtitleConfig.hitokoto || {};

// If hitokoto is enabled on the home page, hide text content initially
// so page content + subtitle appear together after first fetch
let revealContent = null;

if (hitokotoConfig.enable) {
  const root = window.config?.root || '/';
  if (location.pathname === root) {
    const hideStyle = document.createElement('style');
    hideStyle.id = 'hitokoto-loading';
    hideStyle.textContent =
      '.home-banner-container .description,.main-content-body{opacity:0}';
    document.head.appendChild(hideStyle);

    revealContent = () => {
      const el = document.getElementById('hitokoto-loading');
      if (el) {
        el.textContent =
          '.home-banner-container .description,.main-content-body{opacity:1;transition:opacity .4s ease}';
        setTimeout(() => el.remove(), 500);
      }
    };
  }
}

